const item = $input.first().json;
const reportTitle = item.report_title ?? 'تقرير PDF';
const reportType  = item.report_type  ?? 'تحليل شامل';
const pdfBase64   = item.pdf_base64   ?? '';
const LOGO_URL = 'https://i.ibb.co/bg5sQWdC/Picture11.png';
const systemPrompt = 'أنت مصمم تقارير احترافي لعيادة Dr. Tooth Clinic.
استخرج كل البيانات من الـ PDF بدون استثناء. لا هلوسة — فقط ما هو موجود في الـ PDF.
لا تضيف ملاحظات أو توصيات أو تحليل من عندك — اكتفِ بالبيانات الموجودة في الـ PDF فقط.
ملاحظة: استخدم كلمة "مراجعين" بدلاً من "مرضى" في كل مكان في التقرير.

1. اللوجو أول شيء — بانر كامل العرض من أول الصفحة لآخرها:
<div style="width:100%;margin:0;padding:0;background:#0D1B2A;text-align:center;line-height:0;"><img src="' + LOGO_URL + '" style="width:100%;height:auto;display:block;object-fit:cover;"></div>
اللوجو لازم يمتد من الحافة اليمنى للحافة اليسرى بدون أي margin أو padding — عرض كامل 100%
تأكد إن body و html فيهم margin:0 و padding:0

2. الهيدر: background:#0D1B2A — عنوان + "تقرير شهر [الشهر] - [الفرع]" فقط بدون أي نص إضافي مثل "تقرير PDF" أو أي زرار

3. الخط: Cairo من Google Fonts

4. KPIs — مهم جداً: استخرج كل KPI موجود في الـ PDF بدون استثناء ولا نقصان. كل رقم أو نسبة موجودة في الـ PDF لازم تظهر. اعرضها كبطاقات في صف واحد (flex-wrap:wrap) — كل بطاقة: خلفية بيضاء، border-radius:12px، shadow خفيف، padding:20px، min-width:200px. العنوان فوق بخط 14px رمادي والرقم تحته بخط 38px font-weight:900 لون #0A2E3E. لو في 4 KPIs أو أقل اعرضهم في صف واحد. لو أكتر اعرضهم في صفين.

5. لا تضيف جدول فواتير — اعرض البيانات في الشارتات فقط

6. ثلاثة شارتات أعمدة أفقية (لو البيانات موجودة في الـ PDF):
الشارتات: المواعيد — الفواتير — فتح الملفات
كل شارت بلون مختلف: المواعيد (#0D1B2A) — الفواتير (#0d9e6e) — فتح الملفات (#1a6b8a)
كل شارت يعرض كل المنسقين بدون استثناء
كل شارت داخل div منفصل بعرض 100% وخلفية #f8f9fa وborder-radius:12px وpadding:20px وmargin-bottom:20px
عنوان الشارت بخط Cairo عريض وحجم 18px
شكل كل صف بالضبط:
<div style="display:flex;align-items:center;gap:12px;margin-bottom:8px;direction:rtl;"><span style="min-width:160px;font-size:13px;font-weight:600;color:#1a1f2e;text-align:right;white-space:nowrap;">[اسم المنسق]</span><div style="flex:1;height:28px;background:#e9ecef;border-radius:6px;overflow:hidden;"><div style="height:100%;width:[النسبة]%;background:[لون الشارت];border-radius:6px;transition:width 0.5s;"></div></div><span style="min-width:50px;font-size:13px;font-weight:700;color:#1a1f2e;text-align:left;">[النسبة]%</span></div>
العمود الملون فقط هو اللي يمتلئ بالنسبة — الباقي رمادي فاتح #e9ecef
لا تضع أي نص داخل العمود — النسبة تظهر بعد العمود على اليسار فقط

7. footer: "فريق تحليل البيانات قسم التشغيل" فقط

8. أرجع HTML كامل فقط — لا backticks — لا markdown — تأكد من html,body{margin:0;padding:0;}

نوع التقرير: ' + reportType + '
عنوان التقرير: ' + reportTitle;
let messages;
if (pdfBase64 && pdfBase64.length > 100) {
  messages = [{ role: 'user', content: [
    { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } },
    { type: 'text', text: 'استخرج كل البيانات وأنشئ تقرير HTML بعنوان "' + reportTitle + '". لا تخترع بيانات. تأكد من استخراج كل KPI بدون نقصان.' }
  ]}];
} else {
  messages = [{ role: 'user', content: 'أنشئ تقرير HTML بعنوان "' + reportTitle + '": ' + (item.text_content ?? '') }];
}
const requestBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 8000,
  system: systemPrompt,
  messages: messages
};
return [{ json: { requestBody, report_title: reportTitle, pdf_base64: pdfBase64, system_prompt: systemPrompt } }];

const apiRes = $input.first().json;
const prepData = $('Prepare Generate').first().json;
let html = apiRes.content?.[0]?.text ?? '';
html = html.replace(/```html\n?/gi,'').replace(/```\n?/gi,'').trim();
return [{ json: {
  html_content: html,
  report_title: prepData.report_title,
  pdf_base64: prepData.pdf_base64,
  system_prompt: prepData.system_prompt
} }];

const item = $input.first().json;
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 300,
  messages: [{ role: 'user', content: 'راجع هذا التقرير وأجب بـ JSON فقط:\n{"complete": true, "missing": []}\n\n' + item.html_content.substring(0, 5000) }]
});
return [{ json: { requestBody, html_content: item.html_content, report_title: item.report_title, pdf_base64: item.pdf_base64, system_prompt: item.system_prompt } }];

const apiRes = $input.first().json;
const prepData = $('Prepare Review').first().json;
let reviewText = apiRes.content?.[0]?.text ?? '';
let result;
try {
  result = JSON.parse(reviewText.replace(/```json\n?/gi,'').replace(/```\n?/gi,'').trim());
} catch(e) {
  result = { complete: true, missing: [] };
}
return [{ json: {
  is_complete: result.complete,
  missing: result.missing ?? [],
  html_content: prepData.html_content,
  report_title: prepData.report_title,
  pdf_base64: prepData.pdf_base64,
  system_prompt: prepData.system_prompt
} }];

const item = $input.first().json;
const missing = item.missing.join('\n- ');
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 8000,
  system: item.system_prompt,
  messages: [{ role: 'user', content: [
    { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: item.pdf_base64 } },
    { type: 'text', text: 'التقرير ناقص. النواقص:\n- ' + missing + '\n\nأعد إنشاء التقرير كامل مع إصلاح كل النواقص.' }
  ] }]
});
return [{ json: { requestBody, report_title: item.report_title } }];

const apiRes = $input.first().json;
const prepData = $('Prepare Fix').first().json;
let html = apiRes.content?.[0]?.text ?? '';
html = html.replace(/```html\n?/gi,'').replace(/```\n?/gi,'').trim();
return [{ json: { html_content: html, report_title: prepData.report_title } }];
